$client = new Gando\Partner\Client(['apiKey' => getenv('GANDO_API_KEY')]);
$accounts = $client->accounts->list([
    'status' => 'active', // active | revoked | all
    'page' => 1,
    'limit' => 20,
]);

$client = new Gando\Partner\Client(['apiKey' => getenv('GANDO_API_KEY')]);
// Optional: pass idempotencyKey in request options (UUID v4)
$clientRecord = $client->clients->create([
    'accountId' => 'acc_7k2m9x',
    'firstName' => 'Jean',
    'lastName' => 'Dupont',
    'email' => 'jean.dupont@example.com',
    'clientType' => 'particulier',
    // ...
]);

$client = new Gando\Partner\Client(['apiKey' => getenv('GANDO_API_KEY')]);
// Optional: pass idempotencyKey in request options (UUID v4)
$deposit = $client->deposits->create([
    'accountId' => 'acc_7k2m9x',
    'amount' => 800,
    'rentalContract' => 'CTR-2026-0421',
    'contractStartAt' => '2026-06-01T10:00:00.000Z',
    'contractEndAt' => '2026-06-15T18:00:00.000Z',
    'clientId' => 'cli_9f3k2a',
    'depositUrlGeneration' => true,
    'returnUrl' => 'https://partner.example.com/deposits/return',
    // ...
]);

$client = new Gando\Partner\Client(['apiKey' => getenv('GANDO_API_KEY')]);
// Reassign client:
$deposit = $client->deposits->update('dep_abc123', [
    'clientId' => 'cli_9f3k2a',
]);
// Or void in-flight payment (status cancelled):
// $deposit = $client->deposits->update('dep_abc123', ['action' => 'cancel']);

$client = new Gando\Partner\Client(['apiKey' => getenv('GANDO_API_KEY')]);
// Optional: pass idempotencyKey in request options (UUID v4)
$result = $client->deposits->cancel('dep_abc123');

$client = new Gando\Partner\Client(['apiKey' => getenv('GANDO_API_KEY')]);
// Optional: pass idempotencyKey in request options (UUID v4)
$result = $client->deposits->capture('dep_abc123', [
    'amount' => 50000, // cents (min 1000)
    'reason' => 'Vehicle damage',
]);
